def get_oritone_colormap(name: str) -> ListedColormap:
    """Return a Matplotlib ListedColormap by Oritone key, e.g. "oritone-fusion"."""
    if name not in ORITONE_COLORMAPS:
        raise KeyError(f"Unknown Oritone colormap: {name}")
    return ListedColormap(ORITONE_COLORMAPS[name], name=name)


def register_oritone_colormaps() -> None:
    """Register Oritone colormaps with Matplotlib if not already registered."""
    for name in ORITONE_COLORMAPS:
        cmap = get_oritone_colormap(name)
        try:
            mpl.colormaps.register(cmap, name=name, force=False)
        except ValueError:
            pass
